    t2new.abab += einsum(t1.bb, (0, 1), tmp128, (2, 3, 0, 4), (2, 3, 4, 1)) * -1
    del tmp128
    tmp129 = einsum(t1.bb, (0, 1), v.aabb.vvvv, (2, 3, 4, 1), (0, 2, 3, 4))
    t2new.abab += einsum(t1.aa, (0, 1), tmp129, (2, 3, 1, 4), (0, 2, 3, 4))
    del tmp129
    tmp130 = einsum(t1.aa, (0, 1), tmp26, (2, 3, 4, 1), (0, 2, 3, 4))
    del tmp26
    t2new.abab += einsum(tmp130, (0, 1, 2, 3), tmp15, (1, 3, 4, 5), (0, 2, 4, 5))
    del tmp130, tmp15
    tmp131 = einsum(t1.aa, (0, 1), tmp99, (2, 3, 1, 4), (0, 2, 3, 4))
    del tmp99
    t2new.abab += einsum(tmp131, (0, 1, 2, 3), t1.aa, (1, 4), (0, 2, 4, 3)) * -1
    del tmp131

    return {"t1new": t1new, "t2new": t2new}

